---req
function ModelDungeonDaily:DailyBraveMessageReq(type)
    local pb = LProtoHelper.CreateProto(LProtoIds.DailyBraveMessageReq)
    pb.braveType = type
    SendMessage(pb, LProtoIds.DailyBraveMessageReq)
end

function ModelDungeonDaily:DailyBraveSweepReq(dungeonType, sweepType, refId)
    local pb = LProtoHelper.CreateProto(LProtoIds.DailyBraveSweepReq)
    pb.braveType = dungeonType
    pb.sweepType = sweepType
    pb.sweepNode = refId

    SendMessage(pb, LProtoIds.DailyBraveSweepReq)
end

