---resp
function ModelDungeonDaily:OnDailyBraveMessageResp(pb)
    local data = {
        braveType = pb.braveType,
        sweepCount = pb.sweepCount,
        freeSweepCount = pb.freeSweepCount,
        beSweepCount = pb.beSweepCount,
        sweepNode = pb.sweepNode,
        battleNode = pb.battleNode,
        extraSweep = self:ParseNetItems(pb.extraSweep)
    }
    self._dungeonDatas[data.braveType] = data
    FireEvent(EventNames.ON_BRAVE_MSG_RET, data)
end

function ModelDungeonDaily:ParseNetItems(items)
    local itemList = {}

    for k, v in ipairs(items) do
        local data = {
            itemId = v.itemId,
            itemNum = tonumber(v.count),
            itemType = v.type,
            isShowEff = v.effect == 1
        }

        table.insert(itemList, data)
    end
    return itemList
end

function ModelDungeonDaily:OnDailyBraveSweepResp(pb)
    local braveType = pb.braveType
    local sweepType = pb.sweepType
    local data = self._dungeonDatas[braveType]
    if not data then
        return
    end
    if sweepType == 1 then
        data.beSweepCount = data.beSweepCount + 1
    elseif sweepType == 2 then
        data.beSweepCount = data.freeSweepCount
    elseif sweepType == 3 then
        data.beSweepCount = data.sweepCount
    end

    FireEvent(EventNames.ON_BRAVE_SWEEP_RET, pb)
end
