function ModelDungeonDaily:IsLimited(refId)
    local data = GameTable.DunDailyMainRef[refId]
    if data then

        local info = {}

        local lvLimit = data.levLimit
        local lv = gModelPlayer:GetPlayerLv()
        local isPass = true
        if lv < lvLimit then
            isPass = false
            local format = ccClientText(12810)
            local str = string.replace(format, lvLimit)
            table.insert(info, str)
        end
        local powerLimit = data.fight
        local power = gModelPower:GetMainPower()
        if power < powerLimit then
            isPass = false
            local powerStr = LUtil.NumberCoversion(powerLimit,true)
            local format = ccClientText(12811)
            local str = string.replace(format, powerStr)
            table.insert(info, str)
        end

        if not isPass then
            local tip = table.concat(info, "\n")
            return isPass, tip
        else
            return isPass
        end
    end
    return false
end
function ModelDungeonDaily:GetSweepCost(netdata)
    local totalCostList = self:GetTotalCostList(netdata)

    local curTimes = netdata.beSweepCount
    local nextTimes = curTimes + 1

    local cnt = #totalCostList
    if cnt > nextTimes then
        return totalCostList[nextTimes]
    else
        return totalCostList[cnt]
    end
end

function ModelDungeonDaily:GetTotalCostList(netdata)
    local type = netdata.braveType
    local totalCostList = {}
    for k, v in ipairs(netdata.extraSweep) do
        table.insert(totalCostList, v)
    end
    local cfgList = self._sweepExpend[type] or {}

    for k, v in ipairs(cfgList) do
        table.insert(totalCostList, v)
    end

    table.sort(totalCostList, function(a, b)
        return a.itemNum < b.itemNum
    end)
    return totalCostList
end

function ModelDungeonDaily:GetOneKeyCost(netdata, onlyFree)
    local costList = self:GetTotalCostList(netdata)
    local curTimes = netdata.beSweepCount
    local totalTimes = netdata.sweepCount

    local freeTimes = netdata.freeSweepCount

    if freeTimes > 0 then
        curTimes = curTimes - freeTimes
        curTimes = curTimes < 0 and 0 or curTimes
        totalTimes = totalTimes - freeTimes
    end

    local totalCost = 0
    local timesCnt = 0
    local costCnt = #costList
    for k = curTimes + 1, totalTimes do
        local cost = nil
        if k > costCnt then
            cost = costList[costCnt]
        else
            cost = costList[k]
        end

        if onlyFree and cost.itemNum ~= 0 then
            break
        end
        --timesCnt = timesCnt + 1
        totalCost = totalCost + cost.itemNum
    end

    if onlyFree then
        if freeTimes > 0 then
            timesCnt = timesCnt + freeTimes - netdata.beSweepCount
        end
    else

        timesCnt = netdata.sweepCount - netdata.beSweepCount
    end

    return timesCnt, totalCost
end

