function ModelDungeonDaily:CheckIsInBattle(refId)
    local parseFunc = function(value)
        return LxDataHelper.ParseNumber_Sign(value, ',')
    end

    local dataList = self:GetConfigValueImpl(ModelDungeonDaily.dailyGameRef, refId, 'combatType', parseFunc)

    for k, v in ipairs(dataList) do
        if gLFightManager:IsCombatTypeInFight(v) then
            return true, v
        end
    end

    return false
end

function ModelDungeonDaily:GetResidueTimeByRefId(ref, info)
    local textStr = ccLngText(ref.timeText)
    local refId = ref.refId
    if refId == 110 then
        --if gModelRaceGame:IsGameRunning() then
        --    return textStr
        --else
        return ""
        --end
    end

    if info == nil then
        return ""
    end

    local timeText = info and info.timeText
    if string.isempty(timeText) then
        return ""
    end

    local timespan
    if refId == 103 then
        ---  2=time=地图=lvl    1=开始，2-剩余
        local timeTextInfo = string.split(timeText, "=")
        local openState = tonumber(timeTextInfo[1])

        timeText = tonumber(timeTextInfo[2]) or 0
        timespan = tonumber(timeText / 1000) - GetTimestamp()
        if timespan < 0 then
            return ""
        end
        local timeStr = LUtil.FormatTimespanCn(timespan)
        local stateStr = openState == 1 and ccClientText(41410) or ccClientText(41411)
        return string.replace(textStr, stateStr, timeStr)
    else
        timespan = (tonumber(timeText) or 0) / 1000 - GetTimestamp()
        if timespan < 0 then
            return ""
        end
        local timeStr = LUtil.FormatTimespanCn(timespan)
        return string.replace(textStr, timeStr)
    end
end

function ModelDungeonDaily:CheckGamePlayIsOpen(ref, info)
    if info == nil then
