function ModelDungeonDaily:GetGamePlayLv(ref, info)
    if info == nil then
        return ""
    end

    local lvStr = ""
    local refId = ref.refId
    if refId == 103 then
        local timeText = info.timeText
        if not string.isempty(timeText) then
            local timeTextInfo = string.split(timeText, "=")
            if #timeTextInfo >= 4 then
                local mapId = tonumber(timeTextInfo[3])
                lvStr = string.replace(ccClientText(41412), gModelFastDreamTrip:GetMapRefNameByMapId(mapId), timeTextInfo[4])
            end
        end
    end
    return lvStr
end

function ModelDungeonDaily:GetText1ByRefId(ref, info)
    if not info then
