function ModelDungeonDaily:GetEndlesText1(text1, str)
    if text1 == "" then
        return ""
    end
    local text1Arr = string.split(text1, "|")
    local strList = {}
    for i, v in ipairs(text1Arr) do
        local arr = string.split(v, "=")
        local titleStr = ccClientText((12812 + tonumber(arr[1])))
        local refId = tonumber(arr[2])
        local id = 0
        if refId > 0 then
            local ref = gModelEndles:GetEndlessCheckpointRefByRefId(refId)
            id = ref.id
        end

        table.insert(strList, string.replace(titleStr, id))
    end
    local fStr = table.concat(strList, "/")
    return string.replace(str, fStr)
end

