function ModelDungeonDaily:GetDreamTripText2(text1, text2, str)
    if text1 == "" then
        return string.replace(str, ccClientText(12820))
    end
    local ref = gModelDreamTrip:GetMapRefByMapId(tonumber(text1))
    if text2 == "" then
        return string.replace(str, ccClientText(12820))
    end

    if not ref then
        return ""
    end

    if gModelDreamTrip:IsEndMapIdx() then
        return string.replace(str, ccClientText(20494))
    end

    return string.replace(str, tonumber(text2) + 1 .. "/" .. ref.count)
end

function ModelDungeonDaily:GetInvasionText2(text1, text2, str)
    if text2 == "" then
        return string.replace(str, ccClientText(12820))
    end
    local arr = string.split(text2, "=")
    if #arr <= 2 then
        str = string.split(str, "/")
        str = str[1]
        local towerRef = GameTable.SnakeTowerPatternRef[tonumber(arr[1])]
        local modeStr = ccLngText(towerRef.name)
        return string.replace(str, modeStr, arr[2])
    else
        local towerRef = GameTable.SnakeTowerPatternRef[tonumber(arr[1])]
        local modeStr1 = ccLngText(towerRef.name)
        towerRef = GameTable.SnakeTowerPatternRef[tonumber(arr[3])]
        local modeStr2 = ccLngText(towerRef.name)
        return string.replace(str, modeStr1, arr[2], modeStr2, arr[4])
    end
end
function ModelDungeonDaily:GetBadgeGameText2(text1, text2, str)
    if text2 == "" or text2 == "0" then
        return string.replace(str, 0)
    end
    local barrier = tonumber(text2)
    local ref = GameTable.BadgeGameBarrierRef[barrier]
    return string.replace(str, ccLngText(ref.name))
end

