--通过refid 获取日常副本通过的关卡名字
function ModelDungeonDaily:GetResultDungeonNameByRefId(refId)
    local firstName, secondName = "", ""
    local mainRef = GameTable.DunDailyMainRef[refId]
    if mainRef then
        local typeRef = GameTable.DunDailyTypeRef[mainRef.dunType]

        if typeRef then
            firstName = typeRef.name
        end

        secondName = mainRef.titleName
    end
    return firstName, secondName
end

