function ModelDungeonDaily:ParseConfig()
    self._sweepExpend = {}
    for k, v in pairs(GameTable.DunDailyTypeRef) do
        local sweepExpend = v.sweepExpend
        local expendList = LxDataHelper.ParseItem_3List(sweepExpend)
        self._sweepExpend[k] = expendList
    end

    self._dungeonReward = {}
    for k, v in pairs(GameTable.DunDailyMainRef) do
        local reward = v.reward
        self._dungeonReward[k] = LxDataHelper.ParseItem(reward)

    end

    self._dailyGameReward = {}
    for k, v in pairs(GameTable.DailyGamePlayRef) do
        local reward = v.reward
        self._dailyGameReward[k] = LxDataHelper.ParseItem(reward)
    end
end
