---红点
function ModelDungeonDaily:CheckShowDungeonRed(type)
    local data = self._dungeonDatas[type]
    if not data then
        return false
    end

    if data.sweepNode <= 0 then
        return false
    end

    local cost = self:GetSweepCost(data)
    if cost.itemNum == 0 then
        return true
    end
    return false
end

---红点--新的逻辑 
function ModelDungeonDaily:CheckShowDungeonRed_New_1(type)
    local data = self._dungeonDatas[type]
    if not data then
        return false
    end

    if data.sweepNode <= 0 then
        return false
    end

    --判断 当前的免费次数 是不是 足够
    local freeGet = data.beSweepCount < data.freeSweepCount   --当前拥有的免费的次数


    return freeGet
end

function ModelDungeonDaily:OpenChallengTypeCache(type)
    if not self._challengTypeOpenSate then
        self._challengTypeOpenSate = {}
    end

    self._challengTypeOpenSate[type] = true
end

---红点--新的逻辑 -- 当前页签是否新的挑战 并且没查看过
function ModelDungeonDaily:SetNetRedPointCache(redPointInfo)
    local moreinfo = JSON.decode(redPointInfo.moreinfo)
    if not self._tabRedpoint then
        self._tabRedpoint = {}
    end
    for k, v in ipairs(moreinfo) do
        self._tabRedpoint[v] = true
    end
end

function ModelDungeonDaily:CheckShowDungeonRed_New_2(type)
    --
    local tabRed = false
    local isOpen = false



    if not self._tabRedpoint then
        tabRed = false
    else
        tabRed = self._tabRedpoint[type]

        if nil == tabRed then
            tabRed = false
        end
    end

    if not self._challengTypeOpenSate then
        isOpen = false
    else
        if nil == self._dungeonDatas or nil == self._dungeonDatas[type] then
            isOpen = false
        else
            local curNode = self._dungeonDatas[type].battleNode
            local sweepNode = self._dungeonDatas[type].sweepNode

            if curNode == sweepNode then
                return false
            end

            local checkDungeonId = 0
            local isPass, info = self:IsLimited(curNode)

            if isPass then
                checkDungeonId = curNode
            else
                return false
            end

            isOpen = self._challengTypeOpenSate[checkDungeonId]
        end


    end

    return tabRed and not isOpen
end


